arg:thesis_1 a arg:Thesis ;
    arg:hasText "I demonstrated patience during a long dentist visit for braces" .

arg:claim_2 a arg:SubClaim ;
    arg:hasText "I waited without complaining while getting braces put on" ;
    arg:supports arg:thesis_1 .

arg:evidence_3 a arg:QuantifiedEvidence ;
    arg:hasText "I waited about NUM1 minutes without complaining" ;
    arg:supports arg:claim_2 .

arg:evidence_4 a arg:QuantifiedEvidence ;
    arg:hasText "The whole process took NUM2 hours and I was surprised I sat there that long" ;
    arg:supports arg:claim_2 .

arg:evidence_5 a arg:Evidence ;
    arg:hasText "The brackets tasted like heated metal and my mouth hurt like crazy" ;
    arg:supports arg:thesis_1 .

arg:structural_6 a arg:Structural ;
    arg:hasText "Chronological retelling of dentist visit from arrival to completion" ;
    arg:contains arg:thesis_1 ;
    arg:contains arg:claim_2 .

