arg:thesis_1 a arg:Thesis ;
    arg:hasText "A spontaneous road trip with friends became one of the most hilarious and memorable experiences despite setbacks" .

arg:claim_2 a arg:SubClaim ;
    arg:hasText "The day started perfectly with beautiful weather and friends playing guitars" ;
    arg:supports arg:thesis_1 .

arg:evidence_3 a arg:Evidence ;
    arg:hasText "Blue skies, warm summer air, sound of children laughing in the street" ;
    arg:supports arg:claim_2 .

arg:claim_4 a arg:SubClaim ;
    arg:hasText "Things went wrong: got lost finding the skate park, rain started, keys locked in car" ;
    arg:supports arg:thesis_1 .

arg:evidence_5 a arg:QuantifiedEvidence ;
    arg:hasText "Drove around for at least an hour looking for the park; AAA took an hour and a half to find them" ;
    arg:supports arg:claim_4 .

arg:counter_6 a arg:Counter ;
    arg:hasText "Everyone was mad and wondering if the trip was a good choice" ;
    arg:counters arg:thesis_1 .

arg:claim_7 a arg:SubClaim ;
    arg:hasText "The trip ended perfectly with a bonfire on the beach, playing guitars, and sharing laughs" ;
    arg:supports arg:thesis_1 ;
    arg:rebuts arg:counter_6 .

arg:evidence_8 a arg:QuantifiedEvidence ;
    arg:hasText "Built a fire over NUM2 feet tall at driftwood bay, NUM1 yards from the house" ;
    arg:supports arg:claim_7 .

arg:claim_9 a arg:SubClaim ;
    arg:hasText "Even though the beginning was not fun, we closed it the only way we could have wanted" ;
    arg:supports arg:thesis_1 ;
    arg:rebuts arg:counter_6 .

