arg:thesis_1 a arg:Thesis ;
    arg:hasText "The effect computers have on people is positive: entertainment, communication, and news access" .

arg:claim_2 a arg:SubClaim ;
    arg:hasText "People are affected by computers positively because they can be entertained through online games and educational websites" ;
    arg:supports arg:thesis_1 .

arg:evidence_3 a arg:Evidence ;
    arg:hasText "Personal example: uses Miniclip for games and participates in fantasy football" ;
    arg:supports arg:claim_2 .

arg:evidence_4 a arg:Evidence ;
    arg:hasText "Younger brother Parker uses learning websites for hours and is actually learning" ;
    arg:supports arg:claim_2 .

arg:evidence_5 a arg:Citation ;
    arg:hasText "Experts say children throughout the world learn more from computers than from textbooks or teachers because screens catch attention" ;
    arg:supports arg:claim_2 .

arg:counter_6 a arg:Counter ;
    arg:hasText "Some people do not always benefit from having a computer; the child is slouching in front of a screen" ;
    arg:counters arg:thesis_1 .

arg:rebuttal_7 a arg:Rebuttal ;
    arg:hasText "Even though slouching in front of a screen, the child is learning, making it worthwhile" ;
    arg:rebuts arg:counter_6 .

arg:claim_8 a arg:SubClaim ;
    arg:hasText "Computers help people communicate with friends and family" ;
    arg:supports arg:thesis_1 .

arg:evidence_9 a arg:Evidence ;
    arg:hasText "Family video chats with brother at college using Skype program to stay in touch" ;
    arg:supports arg:claim_8 .

arg:evidence_10 a arg:QuantifiedEvidence ;
    arg:hasText "Online poll showed 63% communicate via computer, 32% by phone, 16% in person" ;
    arg:supports arg:claim_8 .

arg:claim_11 a arg:SubClaim ;
    arg:hasText "Computers help people receive news about what is happening around the world" ;
    arg:supports arg:thesis_1 .

arg:evidence_12 a arg:Evidence ;
    arg:hasText "Every time opening the internet there is breaking news about war in Iraq and devastation in Haiti" ;
    arg:supports arg:claim_11 .

arg:evidence_13 a arg:QuantifiedEvidence ;
    arg:hasText "Class pie-chart showed 56% of students get news from computers" ;
    arg:supports arg:claim_11 .

arg:evidence_14 a arg:Evidence ;
    arg:hasText "A waiter from Guatemala said he received all his news about his hometown from the internet" ;
    arg:supports arg:claim_11 .

