arg:thesis_1 a arg:Thesis ;
    arg:hasText "The story ends with those lines because Saeng decides if the hibiscus will grow then so will she — the plant symbolizes her hope and adaptation to a new country." ;
    arg:hasScore "0.85"^^xsd:float .

arg:claim_2 a arg:SubClaim ;
    arg:hasText "The hibiscus purchase is a response to Saeng failing the driving test, which crushed her." ;
    arg:hasScore "0.8"^^xsd:float ;
    arg:supports arg:thesis_1 .

arg:claim_3 a arg:SubClaim ;
    arg:hasText "Saeng goes to the greenhouse to find plants similar to those from her homeland to comfort herself." ;
    arg:hasScore "0.75"^^xsd:float ;
    arg:supports arg:claim_2 .

arg:evidence_4 a arg:Citation ;
    arg:hasText "\"In the warm moist shelter of the greenhouse, Saeng broke down and wept.\"" ;
    arg:hasScore "0.85"^^xsd:float ;
    arg:warrants arg:claim_3 .

arg:claim_5 a arg:SubClaim ;
    arg:hasText "Saeng's mother understands the plant's importance and does not scold her for spending money on it." ;
    arg:hasScore "0.8"^^xsd:float ;
    arg:supports arg:thesis_1 .

arg:evidence_6 a arg:Citation ;
    arg:hasText "\"I'm glad you got it,\" Saeng's mom says because she knows it comforts her daughter." ;
    arg:hasScore "0.8"^^xsd:float ;
    arg:warrants arg:claim_5 .

arg:claim_7 a arg:SubClaim ;
    arg:hasText "By planting the hibiscus together, they are planting Saeng's hope to grow — to pass the driving test and succeed in the new country." ;
    arg:hasScore "0.85"^^xsd:float ;
    arg:supports arg:thesis_1 .

arg:claim_8 a arg:SubClaim ;
    arg:hasText "The hibiscus, though not the same as in the old country, has adapted to its new surroundings — just as Saeng can adapt." ;
    arg:hasScore "0.9"^^xsd:float ;
    arg:supports arg:thesis_1 .

arg:evidence_9 a arg:Evidence ;
    arg:hasText "The plant will grow if it can adapt. Saeng can grow if she adapts to this new country." ;
    arg:hasScore "0.85"^^xsd:float ;
    arg:warrants arg:claim_8 .

