arg:thesis_1 a arg:Thesis ;
    arg:hasText "Patience is one of the hardest things to do, but being patient leads to positive outcomes." ;
    arg:hasScore "0.55"^^xsd:float .

arg:claim_2 a arg:SubClaim ;
    arg:hasText "At Cedar Point, the family had to wait an hour and fifteen minutes for the rain to stop to ride the Magnum." ;
    arg:hasScore "0.5"^^xsd:float ;
    arg:supports arg:thesis_1 .

arg:evidence_3 a arg:QuantifiedEvidence ;
    arg:hasText "The wait was an hour and fifteen minutes standing in line without being able to sit down." ;
    arg:hasScore "0.55"^^xsd:float ;
    arg:warrants arg:claim_2 .

arg:claim_4 a arg:SubClaim ;
    arg:hasText "By choosing not to complain, the narrator started forgetting about the wait and the whole family ended up in a good mood after the ride." ;
    arg:hasScore "0.6"^^xsd:float ;
    arg:supports arg:thesis_1 .

arg:claim_5 a arg:SubClaim ;
    arg:hasText "The experience taught the narrator to be more patient with people because of how well everything worked out." ;
    arg:hasScore "0.5"^^xsd:float ;
    arg:supports arg:thesis_1 .

arg:structural_6 a arg:Structural ;
    arg:hasText "Narrative arc: setup at amusement park, complication of rain delay, resolution through patience, lesson learned." ;
    arg:hasScore "0.5"^^xsd:float ;
    arg:contains arg:thesis_1 .

