arg:thesis_1 a arg:Thesis ;
    arg:hasText "Laughter is an important part of life and requires sharing it with others." ;
    arg:hasScore "0.4"^^xsd:float .

arg:claim_2 a arg:SubClaim ;
    arg:hasText "If you don't laugh you must be a very serious person or think the world is boring." ;
    arg:hasScore "0.25"^^xsd:float ;
    arg:supports arg:thesis_1 .

arg:claim_3 a arg:SubClaim ;
    arg:hasText "You need someone to share jokes with, especially when you're in a bad mood." ;
    arg:hasScore "0.35"^^xsd:float ;
    arg:supports arg:thesis_1 .

arg:evidence_4 a arg:Evidence ;
    arg:hasText "The narrator's health teacher taught that families should share and laugh at the dinner table, and after trying it, the family started telling jokes regularly." ;
    arg:hasScore "0.45"^^xsd:float ;
    arg:warrants arg:claim_3 .

arg:claim_5 a arg:SubClaim ;
    arg:hasText "There are many ways to make someone laugh: comedy shows, jokes, tickling, contests." ;
    arg:hasScore "0.3"^^xsd:float ;
    arg:supports arg:thesis_1 .

arg:claim_6 a arg:SubClaim ;
    arg:hasText "Laughter won't solve all your problems but it makes you feel good and forget bad things for a while." ;
    arg:hasScore "0.4"^^xsd:float ;
    arg:supports arg:thesis_1 .

arg:evidence_7 a arg:Evidence ;
    arg:hasText "The narrator heard that if you laugh a lot, supposedly you live longer." ;
    arg:hasScore "0.2"^^xsd:float ;
    arg:warrants arg:claim_6 .

arg:structural_8 a arg:Structural ;
    arg:hasText "Loosely organized essay with personal anecdote, list of methods, and health claim. Lacks coherent structure and contains many mechanical errors." ;
    arg:hasScore "0.3"^^xsd:float ;
    arg:contains arg:thesis_1 .

